{
  "project": "MMS Last Attempt",
  "description": "Metro Maintenance Scheduler - Semantic Zoom Canvas",
  "target": "50 trains x 10 years x ~60k tasks @ 60fps",

  "phases": {
    "phase1_knowledge_extraction": {
      "status": "in_progress",
      "description": "Extract and validate knowledge from previous attempts",
      "tasks": {
        "extract_stack_decisions": false,
        "extract_architecture_decisions": false,
        "extract_failure_patterns": false,
        "extract_working_code": false,
        "consolidate_findings": false,
        "web_validate": false,
        "create_final_spec": false
      }
    },
    "phase2_setup": {
      "status": "pending",
      "description": "Project setup with validated stack",
      "tasks": {
        "install_dependencies": false,
        "configure_vite": false,
        "setup_patternfly": false,
        "setup_r3f": false,
        "create_base_layout": false
      }
    },
    "phase3_core": {
      "status": "pending",
      "description": "Core semantic zoom implementation",
      "tasks": {
        "lod_level_1_heatmap": false,
        "lod_level_2_blocks": false,
        "lod_level_3_cards": false,
        "smooth_transitions": false,
        "performance_60fps": false
      }
    },
    "phase4_polish": {
      "status": "pending",
      "description": "Polish and production readiness",
      "tasks": {
        "error_handling": false,
        "visual_polish": false,
        "production_build": false,
        "demo_ready": false
      }
    }
  },

  "constraints": {
    "required_stack": {
      "react": "19.x",
      "@patternfly/react-core": "6.x",
      "@belt/tools": "latest",
      "@react-three/fiber": "9.x",
      "@react-three/drei": "10.x",
      "three": "0.170+",
      "vite": "6.x"
    },
    "forbidden_packages": [
      "@blueprintjs/*",
      "@zazcart/*",
      "xstate",
      "next",
      "zustand",
      "redux",
      "mobx",
      "react@18"
    ]
  }
}

